member.example:
Bind the Collider material property using a serialized binder field — the target Collider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ColliderMaterialBinder _material;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public PhysicsMaterial _material;
    }


Bind the Collider material property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Collider _collider;
        
        private ColliderMaterialBinder Material =>
            new(_collider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public PhysicsMaterial _material;
    }

Switch the Collider material between two PhysicsMaterial assets using a serialized binder field — the target Collider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ColliderMaterialSwitcherBinder _isActive;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }


Switch the Collider material between two PhysicsMaterial assets by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Collider _collider;
        [SerializeField] private PhysicsMaterial _activeMaterial;
        [SerializeField] private PhysicsMaterial _inactiveMaterial;
        
        private ColliderMaterialSwitcherBinder IsActive => new(
            _collider,
            trueValue: _activeMaterial,
            falseValue: _inactiveMaterial);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }
